insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q045'), 4, 'Split into two identical groups: ($2^{3}$ × 13) × ($2^{3}$ × 13) = 104 × 104');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q045'), 5, 'So $\sqrt{10816}$ = 104, and $\sqrt{108.16}$ = 104 ÷ 10 = 10.4');
