insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('soc-civ-q009', (select id from chapters where code='soc-civ'), 312, 'NCERT Social Science Grade 8', 1, 'easy', 60, 'mcq', 'What does VVPAT stand for in the context of Indian elections?', null, '["Voter Verifiable Paper Audit Trail", "Voter Verification and Polling Audit Technology", "Voting Verification and Paper Audit Trail", "Voter Verification and Paper Audit Technology"]'::jsonb, 0, 'Voter Verifiable Paper Audit Trail', 'VVPAT is a system for verifying electronic votes with a paper trail.  ▸ Textbook: VVPAT is a system that produces a physical paper record, allowing voters to verify that their electronic votes were cast correctly.');
